// Format contacts for HeyReach API
const contacts = $input.all();

// HeyReach lead format
const heyreachLeads = contacts.map(item => {
  const c = item.json;
  return {
    linkedinUrl: c.linkedin_url,
    firstName: c.first_name || '',
    lastName: c.last_name || '',
    email: c.email || '',
    companyName: c.company || '',
    position: c.job_title || '',
    customFields: {
      contact_id: c.contact_id,
      campaign_contact_id: c.campaign_contact_id,
      source: 'alumni_reconnect_q1_2026',
      is_vip: c.is_vip === 1
    }
  };
});

return {
  json: {
    leads: heyreachLeads,
    total_count: heyreachLeads.length,
    vip_count: contacts.filter(c => c.json.is_vip === 1).length,
    contact_ids: contacts.map(c => ({
      contact_id: c.json.contact_id,
      campaign_contact_id: c.json.campaign_contact_id,
      linkedin_url: c.json.linkedin_url
    }))
  }
};

// Get the contact IDs from earlier node
const formatNode = $('Format for HeyReach API').first().json;
const contactIds = formatNode.contact_ids || [];

// Prepare SQL values for batch insert
const channelId = 'cc111111-2222-3333-4444-555566667777'; // LinkedIn channel

// Build VALUES clause
const values = contactIds.map(c => 
  `('${c.campaign_contact_id}', '${channelId}', 'pending')`
).join(',\n  ');

return {
  json: {
    values: values,
    count: contactIds.length,
    vip_count: formatNode.vip_count,
    contact_ids: contactIds
  }
};
